class UniquePairManager:
    def __init__(self):
        # Using a set for O(1) average time complexity
        self.pairs = set()

    def _normalize(self, a, b):
        """Helper to ensure (A, B) and (B, A) are treated as the same."""
        return (a, b) if a < b else (b, a)

    def add_pair(self, a, b):
        normalized = self._normalize(a, b)
        self.pairs.add(normalized)

    def remove_pair(self, a, b):
        normalized = self._normalize(a, b)
        # Using discard to avoid errors if the pair doesn't exist
        self.pairs.discard(normalized)

    def query_pair(self, a, b):
        normalized = self._normalize(a, b)
        return normalized in self.pairs

